import * as React from 'react'

import ReactGodot from 'react-godot'

class GodotIntegration extends React.Component {
  render () {
    return (
      <ReactGodot script='/path/to/myGame.js' pck='/path/to/myGame.pck' />
    )
  }
}

export default GodotIntegration;
